import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.product.Product;

/**
 * A CDS tranche product.
 * <p>
 * A CDS tranche represents a slice of credit risk from a CDS index portfolio, defined by
 * attachment and detachment points that determine the subordination level.
 * The protection buyer periodically pays fixed coupons to the protection seller until the expiry,
 * and in return, receives compensation for losses within the tranche's boundaries.
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * The underlying CDS index.
   * <p>
   * This is the reference portfolio from which the tranche is defined.
   */
  @PropertyDefinition(validate = "notNull")
  private final CdsIndex underlyingIndex;
  /**
   * The attachment point of the tranche.
   * <p>
   * This is the lower bound of the tranche, expressed as a fraction between 0 and 1.
   * For example, 0.03 represents 3% attachment.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double attachmentPoint;
  /**
   * The detachment point of the tranche.
   * <p>
   * This is the upper bound of the tranche, expressed as a fraction between 0 and 1.
   * For example, 0.06 represents 6% detachment.
   * The detachment point must be greater than the attachment point.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double detachmentPoint;

